#include<bits/stdc++.h>
using namespace std;
struct n{
    int m,v;
}a[110];
bool cmp(n x, n y){
    return x.v*y.m>y.v*x.m;
}
int main(void){
	int n,t,c,i; 
	float f=0;
	std::cin>>n>>t,c=t;
	for(i=1;i<=n;i++)std::cin>>a[i].m>>a[i].v;
	sort(a+1,a+n+1,cmp);
	for(i=1;i<=n;i++){
		if(a[i].m>c)break;
		c-=a[i].m;
		f+=a[i].v;
	}
	if(i<n)f+=1.0*c/a[i].m*a[i].v;
	std::printf("%.2f",f);
    return false;
}
